il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=5e5+5;
int n,m,a[MAXN],tag[MAXN];
string ans[MAXN];
string b_and_a(string A,string B)
{
    string ans;
    int a[2505],b[2505],c[2505];
    if(A==B)
    {
        return "0";
    }
    else if((A.size()==B.size()&&A<B)||A.size()<B.size())
    {
        swap(A,B);
        ans+="-";
    }
    int len=max(A.size(),B.size());
    for(int i=A.size()-1,j=1;i>=0;i--,j++)a[j]=A[i]-'0';
    for(int i=B.size()-1,j=1;i>=0;i--,j++)b[j]=B[i]-'0';
    for(int i=1;i<=len;i++){
        c[i]=c[i]+a[i]-b[i];
        if(c[i]<0)c[i]+=10,c[i+1]-=1;
    }
    int len2;
    for(len2=len;len2>=1;len2--){if(c[len2])break;}
    if(len2==0)len2=1;
    for(int i=len2;i>=1;i--)
    {
        ans+=char(c[i]+'0');
    }
    return ans; 
}
string a_and_b(string A,string B)
{
    string ans="";
    if(A[0]=='-'&&B[0]=='-')
    {
        ans="-";
        A=A.substr(1);
        B=B.substr(1);
    }
    else if(A[0]=='-')
    {
        A=A.substr(1);
        swap(A,B);
        return b_and_a(A,B);
    }
    else if(B[0]=='-')
    {
        B=B.substr(1);
        return b_and_a(A,B);
    }
	int a[2500]={0},b[2500]={0},c[2500]={0};
    int len=max(A.size(),B.size());
    for(int i=A.size()-1,j=1;i>=0;--i,++j)
    {
        a[j]=A[i]-'0';
    }
    for(int i=B.size()-1,j=1;i>=0;--i,++j)
    {
        b[j]=B[i]-'0';
    }
    FOR(i,1,len)
    {
        c[i]+=a[i]+b[i];
        c[i+1]=c[i]/10;
        c[i]%=10;
    }
    if(c[len+1])len++;
    ROF(i,len,1)ans+=char(c[i]+'0');
	return ans;
}
string time(string A,string B)
{
    string ans="";
    int a[100000], b[100000], c[100000];
    int lena=A.size(),lenb=B.size();
    for(int i=lena-1;i>=0;i--)
        a[lena-i]=A[i]-'0';
    for(int i=lenb-1;i>=0;i--)
        b[lenb-i]=B[i]-'0';
    int len=lena+lenb;
    for(int i=1;i<=lena;i++)
        for(int j= 1;j<=lenb;j++)
            c[i+j-1]+=a[i]*b[j];
    for(int i=1;i<=len;i++)
    {
        c[i+1]+=c[i]/10;
        c[i]%=10;
    }
    while(c[len]==0)len--;
    for(int i=max(1ll,len);i>=1;i--)
        ans+=c[i]+'0';
    return ans;
}
void push_up(int p)
{
    ans[p]=a_and_b(ans[ls(p)],ans[rs(p)]);
}
void build(int p,int l,int r)
{
    tag[p]=0;
    if(l==r){ans[p]="0";return ;}
    build(ls(p),l,mid);
    build(rs(p),mid+1,r);
    push_up(p);
} 
void f(int p,int l,int r,int k)
{
    tag[p]=tag[p]+k;
    ans[p]=a_and_b(ans[p],time(to_string(k),to_string(r-l+1)));
}
void push_down(int p,int l,int r)
{
    f(ls(p),l,mid,tag[p]);
    f(rs(p),mid+1,r,tag[p]);
    tag[p]=0;
}
void update(int nl,int nr,int l,int r,int p,int k)
{
    if(nl<=l&&r<=nr)
    {
        ans[p]=a_and_b(ans[p],to_string(k*(r-l+1)));
        tag[p]+=k;
        return ;
    }
    push_down(p,l,r);
    if(nl<=mid)update(nl,nr,l,mid,ls(p),k);
    if(nr>mid) update(nl,nr,mid+1,r,rs(p),k);
    push_up(p);
}
string query(int qx,int qy,int l,int r,int p)
{
    string res="0";
    if(qx<=l&&r<=qy)return ans[p];
    push_down(p,l,r);
    if(qx<=mid)res=a_and_b(res,query(qx,qy,l,mid,ls(p)));
    if(qy>mid) res+=a_and_b(res,query(qx,qy,mid+1,r,rs(p)));
    return res;
}
